/* 文件头注释：动态规划 + 前缀和优化 */
#include <bits/stdc++.h>
using namespace std;

const int MOD = 1e9 + 7;

int main() {
    int N, M, x, y;
    cin >> N >> M >> x >> y;

    // dp[i][j] 表示第 i 天训练量为 j 的方案数
    vector<vector<int>> dp(N + 1, vector<int>(M + 1, 0));
    // prefix[i][j] 表示第 i 天训练量 <= j 的方案数
    vector<vector<int>> prefix(N + 1, vector<int>(M + 1, 0));

    // 初始化第 1 天
    for (int j = 1; j <= M; ++j) {
        dp[1][j] = 1;
        prefix[1][j] = prefix[1][j - 1] + dp[1][j];
    }

    // 填充 DP 表
    for (int i = 2; i <= N; ++i) {
        for (int j = 1; j <= M; ++j) {
            if (i == x) {
                if (j == y) {
                    dp[i][j] = prefix[i - 1][j];
                } else {
                    dp[i][j] = 0;
                }
            } else {
                dp[i][j] = prefix[i - 1][j];
            }
            prefix[i][j] = (prefix[i][j - 1] + dp[i][j]) % MOD;
        }
    }

    // 输出结果
    cout << prefix[N][M] << endl;

    return 0;
}

