/* 文件头注释：使用并查集处理分组关系，通过哈希表统计『好战友』数量 */
#include <bits/stdc++.h>
using namespace std;

// 并查集类
class DSU {
public:
    vector<int> parent;
    DSU(int n) {
        parent.resize(n + 1);
        for (int i = 1; i <= n; ++i) {
            parent[i] = i;
        }
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    void unite(int x, int y) {
        int fx = find(x);
        int fy = find(y);
        if (fx != fy) {
            parent[fy] = fx;
        }
    }
};

int main() {
    int n, k;
    cin >> n >> k;

    // 记录每个同学在所有课程中的分组情况
    vector<map<int, int>> group(n + 1);

    for (int i = 0; i < k; ++i) {
